import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface SunData {
  location: string;
  sunrise: string;
  sunset: string;
  goldenHourMorning: string;
  goldenHourEvening: string;
  dayLength: string;
}

export default function Widget() {
  const sunData = response.data as SunData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: 'rgba(255, 255, 255, 0.75)', backdropFilter: 'blur(10px)' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="subtitle1" color="primary">
              {sunData.location}
            </Typography>
            <Divider sx={{ my: 1 }} />
            <Stack spacing={1}>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Sunrise
                </Typography>
                <Typography variant="body1" fontWeight={500}>
                  {sunData.sunrise}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Sunset
                </Typography>
                <Typography variant="body1" fontWeight={500}>
                  {sunData.sunset}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Golden Hour (Morning)
                </Typography>
                <Typography variant="body1" fontWeight={500}>
                  {sunData.goldenHourMorning}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Golden Hour (Evening)
                </Typography>
                <Typography variant="body1" fontWeight={500}>
                  {sunData.goldenHourEvening}
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Day Length
                </Typography>
                <Typography variant="body1" fontWeight={500}>
                  {sunData.dayLength}
                </Typography>
              </Box>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
